import heapq
class Solution:
    def minCost(self, startPos, homePos, rowCosts, colCosts):
        m = len(rowCosts)
        n = len(colCosts)
        sr, sc = startPos
        hr, hc = homePos
        INF = float('inf')
        dist = [[INF] * n for _ in range(m)]
        dist[sr][sc] = 0
        pq = [(0, sr, sc)]
        while pq:
            d, r, c = heapq.heappop(pq)
            if d > dist[r][c]:
                continue
            if r == hr and c == hc:
                return d
            candidates = []
            if r - 1 >= 0:
                candidates.append((r - 1, c, rowCosts[r - 1]))
            if r + 1 < m:
                candidates.append((r + 1, c, rowCosts[r + 1]))
            if c - 1 >= 0:
                candidates.append((r, c - 1, colCosts[c - 1]))
            if c + 1 < n:
                candidates.append((r, c + 1, colCosts[c + 1]))
            for nr, nc, cost in candidates:
                nd = d + cost
                if nd < dist[nr][nc]:
                    dist[nr][nc] = nd
                    heapq.heappush(pq, (nd, nr, nc))
        return dist[hr][hc]

