class Solution:
    def minCost(self, startPos, homePos, rowCosts, colCosts):
        sr, sc = startPos
        hr, hc = homePos
        total = 0
        if hr >= sr:
            for r in range(sr + 1, hr + 1):
                total += rowCosts[r]
        else:
            for r in range(sr - 1, hr - 1, -1):
                total += rowCosts[r]
        if hc >= sc:
            for c in range(sc + 1, hc + 1):
                total += colCosts[c]
        else:
            for c in range(sc - 1, hc - 1, -1):
                total += colCosts[c]
        return total

