var minCost = function(startPos, homePos, rowCosts, colCosts) {
    const [sr, sc] = startPos;
    const [hr, hc] = homePos;
    let total = 0;
    if (hr >= sr) {
        for (let r = sr + 1; r <= hr; r++) total += rowCosts[r];
    } else {
        for (let r = sr - 1; r >= hr; r--) total += rowCosts[r];
    }
    if (hc >= sc) {
        for (let c = sc + 1; c <= hc; c++) total += colCosts[c];
    } else {
        for (let c = sc - 1; c >= hc; c--) total += colCosts[c];
    }
    return total;
};
